import React, { useEffect, useState } from "react";
import Repository from "./Repository";
import {
  PieChart, Pie, Cell,
  BarChart, Bar, XAxis, YAxis, Tooltip, Legend
} from "recharts";
import "./Repositories.css";

const COLORS = ["#4da6ff", "#339966", "#ff9933", "#ff6666", "#9966ff", "#66cccc"];

export default function RepositoriesPage() {
  const [repos, setRepos] = useState([]);
  const [langData, setLangData] = useState([]);
  const [updateData, setUpdateData] = useState([]);
  const [loading, setLoading] = useState(true);
  const username = "unix69";

  useEffect(() => {
    Repository.fetchAllByUsername(username)
      .then(repos => {
        setRepos(repos);
        computeLanguageStats(repos);
        computeUpdateTimeline(repos);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  }, []);

  const computeLanguageStats = (repos) => {
    const langCounts = {};
    repos.forEach(repo => repo.languages.forEach(lang => {
      langCounts[lang] = (langCounts[lang] || 0) + 1;
    }));
    const data = Object.keys(langCounts).map(lang => ({
      name: lang,
      value: langCounts[lang]
    }));
    setLangData(data);
  };

  const computeUpdateTimeline = (repos) => {
    const timeline = {};
    repos.forEach(repo => {
      const month = repo.lastUpdate.toISOString().slice(0, 7);
      timeline[month] = (timeline[month] || 0) + 1;
    });
    const data = Object.keys(timeline).sort().map(month => ({
      month,
      updates: timeline[month]
    }));
    setUpdateData(data);
  };

  return (
    <main className="repositories-page">
      <h1>Repositories Overview</h1>

      <section className="intro-section">
        <p>
          Questa pagina fornisce una panoramica delle repository associate al mio account GitHub. 
          Include informazioni sui linguaggi utilizzati, attività degli aggiornamenti e metadati principali. 
          Qui sotto puoi vedere i nomi delle repository e alcune statistiche aggregate.
        </p>
      </section>

      {loading && <p style={{textAlign: "center"}}>Caricamento repository...</p>}

      {!loading && repos.length > 0 && (
        <>
          <section className="repos-summary">
            <h2 className="blue-title">Elenco repository</h2>
            <div className="repo-names">
              {repos.map(r => (
                <span key={r.id} className="repo-name-pill">{r.name}</span>
              ))}
            </div>
            <p>
              Totale repository: {repos.length} | Stars totali: {repos.reduce((sum,r)=>sum+r.stars,0)} | Forks totali: {repos.reduce((sum,r)=>sum+r.forks,0)}
            </p>
          </section>

          <section className="charts-section">
            <div className="chart-wrapper">
              <h2 className="orange-title">Linguaggi più usati</h2>
              <PieChart width={400} height={300}>
                <Pie
                  data={langData}
                  dataKey="value"
                  nameKey="name"
                  cx="50%"
                  cy="50%"
                  outerRadius={100}
                  label
                >
                  {langData.map((entry, index) => (
                    <Cell key={index} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Legend />
              </PieChart>
            </div>

            <div className="chart-wrapper">
              <h2 className="blue-title">Attività aggiornamenti</h2>
              <BarChart width={500} height={300} data={updateData}>
                <XAxis dataKey="month" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="updates" fill="#3399ff" />
              </BarChart>
            </div>
          </section>
        </>
      )}

      {!loading && repos.length === 0 && (
        <p style={{textAlign: "center"}}>Nessuna repository trovata.</p>
      )}
    </main>
  );
}
